from pathlib import Path
import csv

import cv2


# Repository root:
# video-perception-pipeline/
REPO_ROOT = Path(__file__).resolve().parents[1]

# Input sampled frames generated by the frame sampling pipeline
FRAMES_DIR = REPO_ROOT / "outputs" / "frames"

# Input tracked detections generated by the tracking pipeline
TRACKED_DETECTIONS_CSV = (
    REPO_ROOT / "outputs" / "tracks" / "tracked_detections.csv"
)

# Output directory for prediction/tracking visualizations
PREDICTION_VIS_DIR = (
    REPO_ROOT / "outputs" / "visualizations" / "predictions"
)

# Output directory for short visualization clips
CLIPS_DIR = PREDICTION_VIS_DIR / "clips"

# Clip FPS is low because sampled frames are saved once per second
CLIP_FPS = 2.0


def load_tracked_detections():
    """
    Load tracked detections generated by the tracking pipeline.

    Reads:
        outputs/tracks/tracked_detections.csv

    Returns:
        grouped[video_id][frame_name] = list[detection]
    """

    if not TRACKED_DETECTIONS_CSV.exists():
        raise FileNotFoundError(
            f"Tracked detections not found: {TRACKED_DETECTIONS_CSV}. "
            "Run the tracking pipeline first: python3 src/run_tracking.py"
        )

    grouped = {}

    with open(TRACKED_DETECTIONS_CSV, "r", encoding="utf-8") as f:
        reader = csv.DictReader(f)

        for row in reader:
            video_id = row["video_id"]
            frame_name = row["frame_name"]

            detection = {
                "class_name": row["class_name"],
                "confidence": float(row["confidence"]),
                "x1": float(row["x1"]),
                "y1": float(row["y1"]),
                "x2": float(row["x2"]),
                "y2": float(row["y2"]),
                "track_id": int(row["track_id"]),
                "is_new_track": row["is_new_track"] == "True",
                "matched_iou": float(row["matched_iou"]),
                "missed_frames_before_match": int(
                    row["missed_frames_before_match"]
                ),
            }

            grouped.setdefault(video_id, {})
            grouped[video_id].setdefault(frame_name, [])
            grouped[video_id][frame_name].append(detection)

    return grouped


def draw_detection(image, detection):
    """
    Draw one tracked prediction on the frame.

    The label contains:
    - detected class
    - track ID
    - confidence score
    - tracking status hints
    """

    x1 = int(detection["x1"])
    y1 = int(detection["y1"])
    x2 = int(detection["x2"])
    y2 = int(detection["y2"])

    class_name = detection["class_name"]
    track_id = detection["track_id"]
    confidence = detection["confidence"]

    label = (
        f"{class_name} "
        f"ID:{track_id} "
        f"{confidence:.2f}"
    )

    # Mark tracks that were newly created by the tracking pipeline.
    if detection["is_new_track"]:
        label += " NEW"

    # Mark detections that matched again after missed sampled frames.
    if detection["missed_frames_before_match"] > 0:
        label += " RE-ENTRY?"

    # Draw bounding box.
    cv2.rectangle(
        image,
        (x1, y1),
        (x2, y2),
        (0, 255, 0),
        2,
    )

    # Draw label background.
    label_y = max(20, y1 - 8)

    cv2.rectangle(
        image,
        (x1, label_y - 18),
        (x1 + 260, label_y + 5),
        (0, 255, 0),
        -1,
    )

    # Draw label text.
    cv2.putText(
        image,
        label,
        (x1 + 4, label_y),
        cv2.FONT_HERSHEY_SIMPLEX,
        0.5,
        (0, 0, 0),
        1,
        cv2.LINE_AA,
    )


def draw_frame_header(image, video_id, frame_name, detection_count):
    """
    Draw a header so the visualization is self-explanatory.
    """

    header = (
        f"video={video_id} | frame={frame_name} | "
        f"detections={detection_count}"
    )

    cv2.rectangle(
        image,
        (0, 0),
        (image.shape[1], 32),
        (0, 0, 0),
        -1,
    )

    cv2.putText(
        image,
        header,
        (10, 22),
        cv2.FONT_HERSHEY_SIMPLEX,
        0.6,
        (255, 255, 255),
        1,
        cv2.LINE_AA,
    )


def save_prediction_images(grouped_detections):
    """
    Save annotated prediction images.

    Reads:
        outputs/frames/<video_id>/*.jpg

    Writes:
        outputs/visualizations/predictions/<video_id>/*.jpg
    """

    saved_images_by_video = {}

    for video_id, frames in grouped_detections.items():

        input_frame_dir = FRAMES_DIR / video_id
        output_frame_dir = PREDICTION_VIS_DIR / video_id

        output_frame_dir.mkdir(
            parents=True,
            exist_ok=True,
        )

        if not input_frame_dir.exists():
            raise FileNotFoundError(
                f"Frame directory not found: {input_frame_dir}. "
                "Run the frame sampling pipeline first: "
                "python3 src/sample_frames.py"
            )

        saved_images_by_video[video_id] = []

        for frame_name, detections in sorted(frames.items()):

            input_frame_path = input_frame_dir / frame_name
            output_frame_path = output_frame_dir / frame_name

            image = cv2.imread(str(input_frame_path))

            if image is None:
                raise RuntimeError(
                    f"OpenCV could not read frame: {input_frame_path}"
                )

            for detection in detections:
                draw_detection(image, detection)

            draw_frame_header(
                image=image,
                video_id=video_id,
                frame_name=frame_name,
                detection_count=len(detections),
            )

            cv2.imwrite(
                str(output_frame_path),
                image,
            )

            saved_images_by_video[video_id].append(
                output_frame_path
            )

    return saved_images_by_video


def save_clip(video_id, image_paths):
    """
    Create a short MP4 clip from annotated prediction images.

    This helps inspect:
    - temporal continuity
    - track ID stability
    - object re-entry
    - obvious tracking failures
    """

    if not image_paths:
        return

    CLIPS_DIR.mkdir(
        parents=True,
        exist_ok=True,
    )

    first_image = cv2.imread(str(image_paths[0]))

    if first_image is None:
        raise RuntimeError(
            f"Could not read first visualization image: {image_paths[0]}"
        )

    height, width = first_image.shape[:2]

    clip_path = CLIPS_DIR / f"{video_id}_prediction_clip.mp4"

    fourcc = cv2.VideoWriter_fourcc(*"mp4v")

    writer = cv2.VideoWriter(
        str(clip_path),
        fourcc,
        CLIP_FPS,
        (width, height),
    )

    for image_path in image_paths:
        image = cv2.imread(str(image_path))

        if image is None:
            continue

        writer.write(image)

    writer.release()

    print(f"Prediction clip saved to: {clip_path}")


def main():
    """
    Prediction visualization pipeline.

    1. Load detections generated by the tracking pipeline.
    2. Read sampled frames generated by the frame sampling pipeline.
    3. Draw boxes, labels, confidence scores, and track IDs.
    4. Mark new tracks and possible object re-entry cases.
    5. Save annotated prediction images.
    6. Save one short visualization clip per video.
    """

    PREDICTION_VIS_DIR.mkdir(
        parents=True,
        exist_ok=True,
    )

    grouped_detections = load_tracked_detections()

    saved_images_by_video = save_prediction_images(
        grouped_detections
    )

    for video_id, image_paths in saved_images_by_video.items():
        save_clip(
            video_id=video_id,
            image_paths=image_paths,
        )

    print(
        f"Prediction visualizations saved to: {PREDICTION_VIS_DIR}"
    )


if __name__ == "__main__":
    main()